import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { CLASSIC_RUNTIME_SCRIPT_PATHS } from "../classic-runtime-manifest.module.mjs";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const repoRoot = path.resolve(__dirname, "..", "..");

export const CLASSIC_RUNTIME_BUNDLE_PATH = "scripts/generated/classic-runtime.bundle.js";

function toJsStringLiteral(value) {
  return JSON.stringify(value);
}

export async function buildClassicRuntimeBundle({
  scriptPaths = CLASSIC_RUNTIME_SCRIPT_PATHS,
  outputRelativePath = CLASSIC_RUNTIME_BUNDLE_PATH,
} = {}) {
  const outputPath = path.join(repoRoot, outputRelativePath);
  if (scriptPaths.length === 0) {
    await fs.rm(outputPath, { force: true });
    return {
      outputRelativePath,
      scriptCount: 0,
      bytes: 0,
      skipped: true,
    };
  }

  const chunks = [
    "// AUTO-GENERATED FILE.",
    "// Source: scripts/tools/build-classic-runtime-bundle.mjs",
    "// Do not edit this file directly.",
    "(function () {",
    "  const scriptSources = [",
  ];
  for (const relativePath of scriptPaths) {
    const absolutePath = path.join(repoRoot, relativePath);
    const source = await fs.readFile(absolutePath, "utf8");
    chunks.push(`    { path: ${toJsStringLiteral(relativePath)}, source: ${toJsStringLiteral(source)} },`);
  }
  chunks.push("  ];");
  chunks.push("");
  chunks.push("  function runInlineClassicScript(entry) {");
  chunks.push('    const script = document.createElement("script");');
  chunks.push('    script.type = "text/javascript";');
  chunks.push('    script.dataset.classicRuntimeBundleEntry = entry.path;');
  chunks.push('    script.text = `/* ${entry.path} */\\n${entry.source}`;');
  chunks.push('    (document.head || document.documentElement).appendChild(script);');
  chunks.push("    script.remove();");
  chunks.push("  }");
  chunks.push("");
  chunks.push("  for (const entry of scriptSources) runInlineClassicScript(entry);");
  chunks.push("");
  chunks.push("})();");
  chunks.push("");
  const output = chunks.join("\n");
  await fs.mkdir(path.dirname(outputPath), { recursive: true });
  await fs.writeFile(outputPath, output, "utf8");
  return {
    outputRelativePath,
    scriptCount: scriptPaths.length,
    bytes: Buffer.byteLength(output, "utf8"),
  };
}

if (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {
  buildClassicRuntimeBundle()
    .then((result) => {
      console.log(JSON.stringify(result, null, 2));
    })
    .catch((error) => {
      console.error(error);
      process.exitCode = 1;
    });
}
